    int n, k;
    scanf("%d %d", &n, &k);

    int diffs[1000];
    int count = 0;
    int max_i = (int)ceil(sqrt(n)) + 1;

    for (int i = 1; i <= max_i; i++) {
        if (n % i == 0) {
